'use client';

import React, { useState, useEffect } from 'react';
import { Wholesaler } from '../../../lib/types';
import { getWholesalers, createWholesaler } from '../../../lib/db';
import styles from './wholesalers.module.css';

export default function WholesalerManager() {
  const [wholesalers, setWholesalers] = useState<Wholesaler[]>([]);
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [category, setCategory] = useState('');
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const fetchWholesalers = async () => {
      try {
        const data = await getWholesalers();
        setWholesalers(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchWholesalers();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setSubmitting(true);
    try {
      const newWholesaler = await createWholesaler({
        name,
        phone_number: phone,
        provides_category: category,
      });
      setWholesalers((prev) => [...prev, newWholesaler]);
      setName('');
      setPhone('');
      setCategory('');
    } catch (err) {
      console.error(err);
      alert('Failed to create wholesaler');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h1 className={styles.title}>Wholesaler Manager</h1>
        <p className={styles.subtitle}>Register and maintain contacts for verified bulk inventory suppliers.</p>
      </div>

      <div className={styles.grid}>
        {/* Form Column */}
        <section className="card" style={{ padding: '24px', height: 'fit-content' }}>
          <h2 className={styles.sectionTitle}>Add New Wholesaler</h2>
          <form onSubmit={handleSubmit} className={styles.form}>
            <div className={styles.formGroup}>
              <label className={styles.label}>Company Name *</label>
              <input
                type="text"
                className="input"
                placeholder="e.g. Acme Imports Ltd"
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
              />
            </div>

            <div className={styles.formGroup}>
              <label className={styles.label}>Contact Phone Number</label>
              <input
                type="tel"
                className="input"
                placeholder="e.g. +1 555-0199"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
              />
            </div>

            <div className={styles.formGroup}>
              <label className={styles.label}>Category Provided</label>
              <input
                type="text"
                className="input"
                placeholder="e.g. Clothing, Office Supplies, Groceries"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
              />
            </div>

            <button type="submit" className="btn btn-primary" style={{ width: '100%' }} disabled={submitting}>
              {submitting ? 'Registering...' : 'Register Wholesaler'}
            </button>
          </form>
        </section>

        {/* List Column */}
        <section className={styles.listSection}>
          <h2 className={styles.sectionTitle}>Registered Wholesalers</h2>
          {loading ? (
            <div className={styles.loader}>Loading wholesalers...</div>
          ) : wholesalers.length === 0 ? (
            <div className={styles.emptyState}>
              <p>No wholesalers registered yet. Use the form to add one.</p>
            </div>
          ) : (
            <div className={styles.list}>
              {wholesalers.map((wholesaler) => (
                <div key={wholesaler.id} className={styles.wholesalerCard}>
                  <div className={styles.wholesalerInfo}>
                    <h3 className={styles.wholesalerName}>{wholesaler.name}</h3>
                    <div className={styles.metaRow}>
                      <span className={styles.metaLabel}>Phone:</span>
                      <span className={styles.metaVal}>{wholesaler.phone_number || 'N/A'}</span>
                    </div>
                  </div>
                  {wholesaler.provides_category && (
                    <span className={styles.categoryBadge}>{wholesaler.provides_category}</span>
                  )}
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}
